CREATE TABLE public.business_project_timeline_attachments ( id uuid PRIMARY KEY DEFAULT gen_random_uuid(), timeline_id uuid NOT NULL REFERENCES public.business_project_timeline(id) ON DELETE CASCADE, project_id uuid NOT NULL REFERENCES public.business_projects(id) ON DELETE CASCADE, file_name text NOT NULL, storage_path text NOT NULL, mime_type text, size_bytes bigint, extracted_text text, analysis_json jsonb, created_at timestamptz NOT NULL DEFAULT now(), user_id uuid REFERENCES auth.users(id) )